class QueueUsingStacks:
    def __init__(self):
        self.stack1 = []  # Stack for enqueue operations
        self.stack2 = []  # Stack for dequeue operations

    def enqueue(self, item):
        # Push item onto stack1
        self.stack1.append(item)

    def dequeue(self):
        # If stack2 is empty, transfer elements from stack1 to stack2
        if not self.stack2:
            while self.stack1:
                self.stack2.append(self.stack1.pop())

        # If stack2 is still empty, the queue is empty
        if not self.stack2:
            raise IndexError("dequeue from an empty queue")

        # Pop the top element from stack2
        return self.stack2.pop()

    def peek(self):
        # Ensure stack2 has the current front element
        if not self.stack2:
            while self.stack1:
                self.stack2.append(self.stack1.pop())

        # If stack2 is still empty, the queue is empty
        if not self.stack2:
            raise IndexError("peek from an empty queue")

        # Return the front element without removing it
        return self.stack2[-1]

    def is_empty(self):
        # The queue is empty if both stacks are empty
        return len(self.stack1) == 0 and len(self.stack2) == 0

    def size(self):
        # The size of the queue is the total number of elements in both stacks
        return len(self.stack1) + len(self.stack2)

